"# Simple HTML Form parsing and validation helpers (avoiding wtforms dependency for zero-configuration running)\n\nclass RegistrationForm:\n    def __init__(self, username, password):\n        self.username = username.strip() if username else \"\"\n        self.password = password.strip() if password else \"\"\n        self.errors = {}\n\n    def validate(self):\n        if not self.username:\n            self.errors['username'] = 'Username is required.'\n        elif len(self.username) < 3:\n            self.errors['username'] = 'Username must be at least 3 characters long.'\n        \n        if not self.password:\n            self.errors['password'] = 'Password is required.'\n        elif len(self.password) < 5:\n            self.errors['password'] = 'Password must be at least 5 characters long.'\n            \n        return len(self.errors) == 0\n\nclass LoginForm:\n    def __init__(self, username, password):\n        self.username = username.strip() if username else \"\"\n        self.password = password.strip() if password else \"\"\n        self.errors = {}\n\n    def validate(self):\n        if not self.username:\n            self.errors['username'] = 'Username is required.'\n        if not self.password:\n            self.errors['password'] = 'Password is required.'\n            \n        return len(self.errors) == 0\n"